import{_ as t,o as e,c as o,a2 as s}from"./chunks/framework.C90q7Ucc.js";const h=JSON.parse('{"title":"飞书功能：云文档与交互卡片","description":"","frontmatter":{},"headers":[],"relativePath":"guide/cloud-docs-and-cards.md","filePath":"guide/cloud-docs-and-cards.md","lastUpdated":1780678956000}'),i={name:"guide/cloud-docs-and-cards.md"};function c(d,a,n,l,p,u){return e(),o("div",null,[...a[0]||(a[0]=[s(`<h1 id="飞书功能-云文档与交互卡片" tabindex="-1">飞书功能：云文档与交互卡片 <a class="header-anchor" href="#飞书功能-云文档与交互卡片" aria-label="Permalink to &quot;飞书功能：云文档与交互卡片&quot;">​</a></h1><h2 id="doc-as-chat" tabindex="-1">doc-as-chat <a class="header-anchor" href="#doc-as-chat" aria-label="Permalink to &quot;doc-as-chat&quot;">​</a></h2><p>云文档评论里 @ 机器人后发送 <code>/new [群名] [目录]</code> 会启用显式 doc-as-chat 模式。Bridge 会创建飞书群聊，并获得这份云文档和触发评论的相关信息；后续长线任务在群聊里推进，文档评论只保留入口提示。</p><p>普通云文档评论也可以作为一次 bot 对话入口：用户在评论里 @bot 后，Bridge 会把评论内容交给当前 runtime，并把回复写回同一个评论线程。为了避免误接管整份文档的无关评论，未建立映射前仍需要 @bot 或评论富文本里包含机器人 mention。</p><p>如果 <code>lark-cli</code> 或机器人权限不可用，模型会在云文档评论里明确说明需要补 CLI 绑定或 Drive 权限。云文档评论还会在 turn 开始前给目标 reply 添加 <code>Typing</code> reaction，回复完成后删除。</p><h2 id="表单" tabindex="-1">表单 <a class="header-anchor" href="#表单" aria-label="Permalink to &quot;表单&quot;">​</a></h2><p>通过 <code>codelark-question</code> skill，模型可以让 Bridge 生成飞书 CardKit 2.0 表单，而不只是按钮卡片。协议示例：</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">clk-ask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;{&quot;question&quot;:&quot;请选择发布策略&quot;,&quot;options&quot;:[&quot;灰度&quot;,&quot;全量&quot;],&quot;input&quot;:{&quot;label&quot;:&quot;补充说明&quot;,&quot;placeholder&quot;:&quot;可留空&quot;},&quot;submitText&quot;:&quot;提交&quot;,&quot;allowTextReply&quot;:true}&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">clk-ask</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><p>新提示和新文档使用 <code>&lt;clk-ask&gt;</code>。</p><p>渲染规则：</p><ul><li><code>options</code> 会渲染为一个 <code>select_static</code>。</li><li><code>input</code> 会渲染为可为空的文本框。</li><li>提交按钮使用 <code>form_action_type: &quot;submit&quot;</code>。</li><li>CardKit 2.0 提交值会出现在 raw event 的 <code>action.form_value</code>，key 是控件 <code>name</code>。因此表单控件使用固定 name：<code>clk_choice</code> 与 <code>clk_input</code>。</li></ul><p>用户提交后，Bridge 会把回调转成同一会话里的下一条消息：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[用户回答了问题卡片]</span></span>
<span class="line"><span>问题：请选择发布策略</span></span>
<span class="line"><span>回答：选择：灰度</span></span>
<span class="line"><span>补充：可以先给 10% 用户</span></span></code></pre></div><p>如果补充输入框为空，会显式回传 <code>补充：（空）</code>，让模型知道用户是自由提交而不是消息丢失。</p>`,14)])])}const k=t(i,[["render",c]]);export{h as __pageData,k as default};
